#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard escapeHTML);

my $q = CGI->new;
my $log_dir = '/var/log';

print $q->header('text/html; charset=UTF-8');

my $filename = $q->param('logfile') // '';

print <<'HTML';
<!DOCTYPE html>
<html>
<head>
<title>Log Viewer</title>
</head>
<body>
HTML

if ($filename eq '') {
    print '<h1>No logfile specified</h1>';
    print "</body></html>";
    exit;
}

if ($filename =~ m{[\\/]} || $filename =~ /\A\.+\z/ || $filename =~ /\.\./) {
    print '<h1>Invalid logfile specified</h1>';
    print "</body></html>";
    exit;
}

my $path = "$log_dir/$filename";

if (!-f $path) {
    print '<h1>Log file not found</h1>';
    print "</body></html>";
    exit;
}

if (!open(my $fh, '<', $path)) {
    print '<h1>Unable to open log file</h1>';
    print "</body></html>";
    exit;
}

print '<h1>Viewing Log: ' . escapeHTML($filename) . '</h1>';
print '<pre>';

while (my $line = <$fh>) {
    print escapeHTML($line);
}

close($fh);

print <<'HTML';
</pre>
</body>
</html>
HTML